// Iron Body - Automation Router (produccion)
// Recibe un evento proactivo emitido por Laravel y lo convierte en una
// notificacion segura llamando a /api/internal/automation/notify-member.
//
// Estrategia de mensaje (Fase 2):
//   1) Si Laravel envia data.notification (mensaje PREMIUM/personalizado), se usa.
//   2) Si no, se usa el catalogo de respaldo MESSAGES (generico premium).
// Asi los eventos base (p. ej. nutrition.missing) siguen funcionando igual y los
// nuevos pueden llegar personalizados desde Laravel.
//
// NO accede a PostgreSQL. NO construye contexto IA. NO llama a OpenAI.
// Variables de entorno requeridas en n8n:
//   - LARAVEL_BASE_URL            (https://api.ironbodyneiva.cloud)
//   - AUTOMATION_INTERNAL_SECRET  (mismo valor que el .env de Laravel)
// Si los Code nodes no leen $env, ajustar N8N_BLOCK_ENV_ACCESS_IN_NODE=false.

const items = $input.all();
const item = items[0] || { json: {} };
const j = item.json || {};
const headers = j.headers || {};
const body = j.body || j;
const data = body.data || {};

const eventType =
  headers['x-ironbody-event'] ||
  body.event_type ||
  (body.event && body.event.type) ||
  'default';

const memberId =
  (data.member && data.member.id) ||
  data.member_id ||
  body.member_id ||
  (body.member && body.member.id) ||
  null;

// Catalogo de respaldo (premium, generico, sin PII). type = event_type.
const MESSAGES = {
  // ── Base (ya en produccion: NO cambiar nutrition.missing) ──────────────────
  'nutrition.missing':            { type:'nutrition.missing',            title:'Nutricion pendiente',            body:'Aun no registras tus comidas de hoy. IRON IA puede ayudarte a ajustar tu dia.', action_route:'/iron-ai?focus=nutrition', priority:'normal' },
  'membership.expiring':          { type:'membership.expiring',          title:'Tu membresia esta por vencer',   body:'Revisa tu plan para no perder el acceso al gimnasio.',                            action_route:'/membership',              priority:'high'   },
  'streak.completed':             { type:'streak.completed',             title:'Racha completada',               body:'Buen trabajo. IRON IA puede ayudarte a subir el siguiente nivel.',                action_route:'/iron-ai?focus=progress',  priority:'normal' },
  'evaluation.outdated':          { type:'evaluation.outdated',          title:'Actualiza tu evaluacion',        body:'Tu progreso sera mas preciso si actualizas tus datos fisicos.',                   action_route:'/evaluation',              priority:'normal' },
  'progress.stalled':             { type:'progress.stalled',             title:'Revisemos tu progreso',          body:'IRON IA puede ayudarte a ajustar entrenamiento y nutricion para volver a avanzar.', action_route:'/iron-ai?focus=progress', priority:'normal' },
  'iron_ai.weekly_summary_ready': { type:'iron_ai.weekly_summary_ready', title:'Tu resumen semanal esta listo',  body:'IRON IA analizo tu semana y preparo recomendaciones para mejorar.',               action_route:'/iron-ai?focus=weekly',    priority:'normal' },
  // workout.missed: tono coach evolucionado (Fase 2).
  'workout.missed':               { type:'workout.missed',               title:'No perdamos el ritmo',           body:'Hoy no se completo el entrenamiento. Ven, revisemos como retomarlo sin afectar tu progreso.', action_route:'/iron-ai?focus=workout', priority:'normal' },

  // ── Nuevos (Fase 2) — respaldo generico; Laravel suele enviar personalizado ─
  'workout.not_started_today':    { type:'workout.not_started_today',    title:'Tu entrenamiento te esta esperando', body:'Aun estas a tiempo. Ven, te ayudo a empezar la rutina de hoy sin complicarte.', action_route:'/iron-ai?focus=workout', priority:'normal' },
  'streak.at_risk':               { type:'streak.at_risk',               title:'Tu racha esta en riesgo',        body:'Aun puedes protegerla hoy. Ven, hagamos una accion rapida para mantener el impulso.', action_route:'/iron-ai?focus=streak', priority:'high'   },
  'streak.not_started':           { type:'streak.not_started',           title:'Empieza tu primera racha',       body:'Hoy puede ser tu primer dia de constancia. Ven, te ayudo a comenzar con una accion simple.', action_route:'/iron-ai?focus=streak', priority:'normal' },
  'daily.compliance_missing':     { type:'daily.compliance_missing',     title:'Aun puedes cumplir hoy',         body:'Te falta una accion clave para cerrar el dia mejor. Ven, te ayudo a elegir la mas importante.', action_route:'/iron-ai?focus=today', priority:'normal' },
  'coach.nudge':                  { type:'coach.nudge',                  title:'Tengo una recomendacion para ti', body:'Ven, revisemos juntos que accion te conviene hacer ahora.',                       action_route:'/iron-ai?focus=today',     priority:'normal' },
  'iron_ai.chat_invite':          { type:'iron_ai.chat_invite',          title:'Tu Coach IA puede ayudarte',     body:'Preguntame que entrenar, como comer mejor o como avanzar esta semana. Ven, probemoslo juntos.', action_route:'/iron-ai?focus=chat', priority:'normal' },
  'iron_ai.nutrition_invite':     { type:'iron_ai.nutrition_invite',     title:'Puedo revisar tu nutricion contigo', body:'Ven, analicemos tus comidas y descubramos que puedes mejorar sin complicarte.', action_route:'/iron-ai?focus=nutrition', priority:'normal' },
  'iron_ai.progress_invite':      { type:'iron_ai.progress_invite',      title:'Revisemos tu progreso',          body:'Ven, miremos juntos que esta funcionando y que podriamos ajustar para avanzar mejor.', action_route:'/iron-ai?focus=progress', priority:'normal' },
  'iron_ai.streak_invite':        { type:'iron_ai.streak_invite',        title:'Construyamos constancia',        body:'Tu racha puede ayudarte a mantener disciplina. Ven, te explico como empezar.',   action_route:'/iron-ai?focus=streak',    priority:'normal' },
  'module.discovery':             { type:'module.discovery',             title:'Hay algo nuevo para ti',         body:'Puedo ayudarte a sacarle mas provecho a Iron Body. Ven, descubramos que modulo te conviene usar hoy.', action_route:'/iron-ai?focus=discover', priority:'normal' },
  'coach.reactivation':           { type:'coach.reactivation',           title:'Retomemos sin presion',          body:'No importa cuantos dias pasaron. Ven, te ayudo a volver con una accion simple.',  action_route:'/iron-ai?focus=reactivation', priority:'normal' },
  'weekly.coach_plan':            { type:'weekly.coach_plan',            title:'Planifiquemos tu semana',        body:'Ven, te ayudo a ordenar entrenamiento, nutricion y constancia para avanzar con claridad.', action_route:'/iron-ai?focus=weekly-plan', priority:'normal' }
};

const baseUrl = ($env.LARAVEL_BASE_URL || '').replace(/\/+$/, '');
const secret = $env.AUTOMATION_INTERNAL_SECRET || '';

// 1) Mensaje personalizado de Laravel, si viene; 2) catalogo de respaldo.
const provided = (data && data.notification && typeof data.notification === 'object') ? data.notification : null;
const fallback = MESSAGES[eventType] || null;
const msg = provided || fallback;

function skipped(reason) {
  return [{ json: {
    ok: true, received: true, event_type: eventType, member_id: memberId,
    status: 'skipped', skipped_reason: reason
  } }];
}

if (!baseUrl)  { return skipped('no_base_url'); }
if (!secret)   { return skipped('no_secret'); }
if (!memberId) { return skipped('no_member'); }
if (!msg || !msg.title || !msg.body) { return skipped('unmapped_event'); }

const outPayload = {
  member_id: memberId,
  type: msg.type || eventType,
  title: msg.title,
  body: msg.body,
  action_route: msg.action_route || null,
  priority: msg.priority || 'normal',
  payload: { event_type: eventType, source: 'n8n-automation-router', personalized: provided !== null }
};

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: baseUrl + '/api/internal/automation/notify-member',
  headers: { 'Authorization': 'Bearer ' + secret, 'Content-Type': 'application/json' },
  body: outPayload,
  json: true,
  returnFullResponse: true,
  ignoreHttpStatusErrors: true
});

const code = resp.statusCode || 0;
return [{ json: {
  ok: code >= 200 && code < 300,
  received: true,
  event_type: eventType,
  member_id: memberId,
  status: 'sent',
  laravel_status: code,
  laravel: resp.body
} }];
